document.addEventListener("DOMContentLoaded",(()=>{console.log("DOM loaded"),"function"==typeof initSlideshow&&initSlideshow(),"function"==typeof initAnimations&&initAnimations(),"function"==typeof initMobileMenu&&initMobileMenu();const n=document.querySelector("main");window.addEventListener("scroll",(()=>{window.scrollY>50?n.classList.add("scrolled"):n.classList.remove("scrolled")}))}));
// Verifica se il browser supporta il Service Worker
if ('serviceWorker' in navigator) {
    navigator.serviceWorker.register('/Fabiolas-Restaurant/service-worker.js')  // Usa il percorso corretto
        .then(registration => {
            console.log('Service Worker registrato con successo:', registration);
        })
        .catch(error => {
            console.error('Errore durante la registrazione del Service Worker:', error);
        });
}
